UnityUnrealC++Python <pre><code>// 1. Attach TryllAgentComponent to a GameObject.
//    Assign a TryllWorkflowAsset in the Inspector, or build the graph at runtime:
var graph = new TryllGraphBuilder()
    .AddHumanMessageGuardrail("guard", new TryllHumanMessageGuardrailParams
    {
        // TriggeredExit is "" (END) by default — drop jailbreaks silently.
        NotTriggeredExit = "answer",
    })
    .AddGenerate("answer", new TryllGenerateParams())
    .SetStartNode("guard")
    .SetDefaultModelName("My Local Model")
    .Build();

var agentComp = GetComponent&lt;TryllAgentComponent&gt;();
agentComp.InlineGraphDescription = graph;

// 2. Wire events.
agentComp.OnAnswerText.AddListener(
    (text, isDelta, isFinal) =&gt; chatText.text += text);
agentComp.OnTurnComplete.AddListener(
    (status, _, _) =&gt; typingIndicator.SetActive(false));

// 3. When the agent is created, send the first message.
agentComp.OnAgentCreated.AddListener(() =&gt; agentComp.SendMessage("Hello!"));
</code></pre> <ol> <li>Add a <code>UTryllAgentComponent</code> to your actor.</li> <li>In the Details panel, edit Graph on the component, or    reference a <code>UTryllWorkflowAsset</code> you authored in the Content    Browser. On the guard node, set Triggered Exit to    <code>""</code> (END) and Not Triggered Exit to <code>"answer"</code>. The    answer node's Default Exit can be left empty (END).</li> <li>In Blueprint:<ul> <li>Bind On Agent Ready to a handler that calls Send   Message.</li> <li>Bind On Answer Text to append each chunk to a UI text   block.</li> <li>Bind On Turn Complete to flip the "typing" indicator   off.</li> </ul> </li> </ol> <pre><code>#include &lt;tryll/TryllClient.h&gt;

namespace TC = Tryll::Client;

TC::HumanMessageGuardrailParams guardParams;
// guardParams.triggered_exit defaults to "" (END) — drop jailbreaks silently.
guardParams.not_triggered_exit = "answer";

TC::GraphDescription graph;
graph.AddNode("guard",  guardParams)
     .AddNode("answer", TC::GenerateParams{})
     .SetStartNode("guard")
     .SetDefaultModelName("My Local Model");

auto agent = client.CreateAgent(graph);

// Register persistent callbacks, then send — fire-and-forget.
agent.SetOnAnswerText([](std::string_view text, bool, bool)
    { std::cout &lt;&lt; text &lt;&lt; std::flush; });
agent.SetOnTurnComplete([](TC::TurnStatus, std::string_view, std::int32_t)
    { std::cout &lt;&lt; "\n"; });
agent.SendText("Hello!");
</code></pre> <pre><code>from tryll_client.graph import GraphDescription, HumanMessageGuardrailParams, GenerateParams

# 1. Build the graph.
guard_params = HumanMessageGuardrailParams(
    # triggered_exit defaults to "" (END) — drop jailbreaks silently.
    not_triggered_exit = "answer",
)

graph = (
    GraphDescription()
    .add_node("guard",  guard_params)
    .add_node("answer", GenerateParams())
    .set_start_node("guard")
    .set_default_model_name("My Local Model")
)

# 2. Create the agent.
agent = client.create_agent(graph)

# 3. Send a message. send_message blocks and returns the full reply.
reply = agent.send_message("Hello!")
print(reply)
</code></pre>

UnityUnrealC++Python <pre><code>using Tryll.Client;

var agentComp = GetComponent&lt;TryllAgentComponent&gt;();

// Clone the baseline, change one field, send.
var p = (TryllGenerateParams)agentComp.Agent.GetNodeParamsBaseline("answer").Clone();
p.SystemPrompt = "You are a pirate.";
agentComp.Agent.ChangeParams("answer", p,
    err =&gt; {
        if (err == null)
            Debug.Log("Persona updated");
        else
            Debug.LogError($"Error {err.Code}: {err.Message}");
    });

// Relax the retrieval threshold.
var rp = (TryllRetrieveParams)agentComp.Agent.GetNodeParamsBaseline("knowledge").Clone();
rp.Threshold = 0.9f;
agentComp.Agent.ChangeParams("knowledge", rp);

// Turn on streaming.
var gp = (TryllGenerateParams)agentComp.Agent.GetNodeParamsBaseline("answer").Clone();
gp.Stream = true;
agentComp.Agent.ChangeParams("answer", gp);
</code></pre> C++Blueprint <pre><code>#include "Generated/Nodes/TryllGenerateParams.h"
#include "Generated/Nodes/TryllNodeParamsFactory.h"

// Clone the baseline, change one field, send.
UTryllNodeParamsBase* Base = AgentComponent-&gt;GetNodeParamsBaseline(TEXT("answer"));
UTryllGenerateParams* P = Cast&lt;UTryllGenerateParams&gt;(
    UTryllNodeParamsFactory::CloneParams(Base, this));
P-&gt;SystemPrompt = TEXT("You are a pirate.");
AgentComponent-&gt;ChangeParams(
    TEXT("answer"), P,
    [](const FTryllError&amp; Err)
    {
