UnityUnrealC++Python <p>On <code>TryllAgentComponent</code>, bind two events. All callbacks fire on the Unity main thread — you can update UGUI / UI Toolkit widgets directly without marshalling.</p> <pre><code>var agentComp = GetComponent&lt;TryllAgentComponent&gt;();

// OnAnswerText fires for every streamed chunk.
agentComp.OnAnswerText.AddListener((text, isDelta, isFinal) =&gt;
{
    chatBubble.AppendText(text);
    if (isFinal) chatBubble.HideCursor();
});

// OnTurnComplete fires once the turn ends.
agentComp.OnTurnComplete.AddListener((status, _, _) =&gt;
{
    typingIndicator.SetActive(false);
    chatBubble.CommitReply();
});
</code></pre> <p>On the <code>UTryllAgentComponent</code>, bind two events in Blueprint:</p> <ul> <li>On Answer Text (Text: FString, bIsFinal: bool) — append   <code>Text</code> to your <code>UTextBlock</code>. <code>bIsFinal</code> is <code>true</code> only on the   very last chunk.</li> <li>On Turn Complete (Status: ETryllTurnStatus) — stop the   typing indicator and commit the final reply.</li> </ul> <p>There is also On Answer Full (FullText: FString) which fires once after the turn completes, with the whole response in one string — useful if your UI only needs the final text.</p> <p>Register <code>SetOnAnswerText</code> before calling <code>SendText</code>. <code>SetOnAnswerText</code> fires on the client library's reader thread for each streamed chunk and once more with <code>isFinal = true</code> on the last chunk.  <code>SendText</code> is fire-and-forget; use <code>SetOnTurnComplete</code> to know when the turn is finished.</p> <pre><code>std::string buffer;

agent.SetOnAnswerText(
    [&amp;](std::string_view text, bool /*isDelta*/, bool isFinal)
    {
        buffer.append(text);
        YourChatWidget::SetCurrentReply(buffer);
        if (isFinal)
        {
            YourChatWidget::CommitReply(buffer);
            buffer.clear();
        }
    });

agent.SetOnTurnComplete(
    [](::Tryll::TurnStatus, std::string_view, std::int32_t) {});

agent.SendText("Tell me about the architecture.");
</code></pre> <p>Python does not expose per-chunk streaming today.</p> <p><code>TryllClient.send_message</code> blocks until the server sends <code>TurnComplete</code> and returns the complete reply text. Streaming chunks arrive over the wire and are accumulated inside the client, but there is no user callback for each chunk. Use Unity, C++, or Unreal when you need a per-token UI.</p> <pre><code># Blocks, accumulates all AnswerText chunks, returns the full reply.
reply = agent.send_message("Tell me about the architecture.")
your_chat_widget.set_current_reply(reply)

# Diagnostics about the last turn:
print(agent.last_tokens_generated,
      agent.last_answer_chunk_count,
      agent.last_ttft_s)
</code></pre>

UnityUnrealC++Python <pre><code>// 1. Create storages.
await TryllClient.Instance.RequestCreateStringStorageAsync(
    "jailbreak_patterns",
    new List&lt;string&gt; {
        @"ignore\s+previous\s+instructions?",
        @"you\s+are\s+DAN",
        @"pretend\s+to\s+be",
    });

await TryllClient.Instance.RequestCreateStringStorageAsync(
    "refusal_lines",
    new List&lt;string&gt; {
        "I can't help with that request.",
        "That's outside what I can assist with.",
    });

// 2. Build the graph.
//    Exits pointing to END are the default (empty string) — no need to set them.
var graph = new TryllGraphBuilder()
    .AddHumanMessageGuardrail("guard", new TryllHumanMessageGuardrailParams
    {
        StringStorage    = "jailbreak_patterns",
        TriggeredExit    = "refuse",
        NotTriggeredExit = "answer",
    })
    .AddCannedResponse("refuse", new TryllCannedResponseParams
    {
        StringStorage = "refusal_lines",
        // DefaultExit is "" (END) by default.
    })
    .AddGenerate("answer", new TryllGenerateParams())
    .SetStartNode("guard")
    .SetDefaultModelName("My Local Model")
    .Build();

var (agent, error) = await TryllClient.Instance.RequestCreateAgentAsync(graph);
</code></pre> <ol> <li>Call <code>UTryllSubsystem::CreateStringStorage</code> twice — once for    patterns, once for refusal lines. Bind    On Create String Storage Complete for each and wait for    <code>bSuccess</code>.</li> <li>In a <code>UTryllWorkflowAsset</code> (or directly on the component's    Graph details panel), build the three-node graph with the    <code>string_storage</code> parameter set on the guardrail and the    canned-response nodes.</li> </ol> <pre><code>namespace TC = Tryll::Client;

// 1. Storages
client.CreateStringStorage("jailbreak_patterns", {
    R"(ignore\s+previous\s+instructions?)",
    R"(you\s+are\s+DAN)",
});
client.CreateStringStorage("refusal_lines", {
    "I can't help with that request.",
    "That's outside what I can assist with.",
});

// 2. Graph — exits pointing to END are the default (empty string).
TC::HumanMessageGuardrailParams guardParams;
guardParams.string_storage     = "jailbreak_patterns";
guardParams.triggered_exit     = "refuse";
guardParams.not_triggered_exit = "answer";

TC::CannedResponseParams refuseParams;
refuseParams.string_storage = "refusal_lines";
// refuseParams.default_exit defaults to "" (END)

TC::GraphDescription graph;
graph.AddNode("guard",  guardParams)
     .AddNode("refuse", refuseParams)
     .AddNode("answer", TC::GenerateParams{})
     .SetStartNode("guard")
     .SetDefaultModelName("My Local Model");

auto agent = client.CreateAgent(graph);
</code></pre> <pre><code>from tryll_client.graph import (
    GraphDescription, HumanMessageGuardrailParams,
    CannedResponseParams, GenerateParams,
)

# 1. Define the patterns and the refusal lines as string storages.
#    These die with the session; recreate on reconnect.
client.create_string_storage(
    name="jailbreak_patterns",
    strings=[
        r"ignore\s+previous\s+instructions?",
        r"you\s+are\s+DAN",
        r"pretend\s+to\s+be",
    ],
)

client.create_string_storage(
    name="refusal_lines",
    strings=[
        "I can't help with that request.",
        "That's outside what I can assist with.",
    ],
)

# 2. Build the graph — exits pointing to END are the default (empty string).
graph = (
    GraphDescription()
    .add_node("guard", HumanMessageGuardrailParams(
        string_storage="jailbreak_patterns",
        triggered_exit="refuse",
        not_triggered_exit="answer",
    ))
    .add_node("refuse", CannedResponseParams(
        string_storage="refusal_lines",
        # default_exit is "" (END) by default.
    ))
    .add_node("answer", GenerateParams())
    .set_start_node("guard")
    .set_default_model_name("My Local Model")
)

agent = client.create_agent(graph)
</code></pre>

